+      return node.textContent != null ? node.textContent : "";
+    }
+
+    if (node.nodeType !== Node.ELEMENT_NODE) {
+      return "";
+    }
+
+    var element = node;
+    var tagName = element.tagName.toUpperCase();
+
+    if (
+      tagName === "BUTTON" ||
+      tagName === "SVG" ||
+      tagName === "PATH" ||
+      tagName === "USE" ||
+      tagName === "IMG" ||
+      tagName === "NOSCRIPT"
+    ) {
+      return "";
+    }
+
+    if (tagName === "BR") {
+      return "\\n";
+    }
+
+    var childText = Array.from(element.childNodes)
