  1→import {
  2→  type Conversation,
  3→  conversationSchema,
  4→  type SourcePlatform,
  5→} from "@chat-exporter/shared";
  6→import { JSDOM } from "jsdom";
  7→import { DOM_KIT_SCRIPT } from "./parser-dom-kit.js";
  8→
  9→export type ClipboardImportResult = {
 10→  conversation: Conversation;
 11→  warnings: string[];
 12→  detectedPlatform: SourcePlatform;
 13→};
 14→
 15→/**
 16→ * Import a conversation from clipboard content (HTML and/or plain text).
 17→ * No browser required — uses JSDOM for HTML parsing.
 18→ */
 19→export async function importFromClipboard(input: {
 20→  html?: string;
 21→  plainText?: string;
 22→}): Promise<ClipboardImportResult> {
 23→  const warnings: string[] = [];
 24→
 25→  if (input.html) {
 26→    return importFromClipboardHtml(input.html, warnings);
 27→  }
 28→
 29→  if (input.plainText) {
 30→    return importFromClipboardText(input.plainText, warnings);
 31→  }
 32→
 33→  throw new Error("Either html or plainText must be provided");
 34→}
 35→
 36→// ---------------------------------------------------------------------------
 37→// Platform detection
 38→// ---------------------------------------------------------------------------
 39→
 40→export function detectPlatformFromHtml(html: string): SourcePlatform {
 41→  const lower = html.toLowerCase();
 42→
 43→  if (lower.includes("data-message-author-role")) return "chatgpt";
 44→  if (lower.includes("font-claude-message") || lower.includes("claude.ai"))
 45→    return "claude";
 46→  if (lower.includes("share-turn-viewer") || lower.includes("gemini"))
 47→    return "gemini";
 48→  if (lower.includes("grok")) return "grok";
 49→  if (lower.includes("deepseek")) return "deepseek";
 50→  if (lower.includes("perplexity")) return "perplexity";
 51→  if (lower.includes("mistral") || lower.includes("lechat")) return "lechat";
 52→
 53→  return "unknown";
 54→}
 55→
 56→// ---------------------------------------------------------------------------
 57→// HTML path
 58→// ---------------------------------------------------------------------------
 59→
 60→function importFromClipboardHtml(
 61→  html: string,
 62→  warnings: string[],
 63→): ClipboardImportResult {
 64→  const platform = detectPlatformFromHtml(html);
 65→
 66→  if (platform === "unknown") {
 67→    warnings.push("Could not detect platform from clipboard HTML");
 68→  }
 69→
 70→  const dom = new JSDOM(html, { runScripts: "dangerously" });
 71→  const { window } = dom;
 72→
 73→  // Inject DOM kit script into JSDOM
 74→  const scriptEl = window.document.createElement("script");
 75→  scriptEl.textContent = DOM_KIT_SCRIPT;
 76→  window.document.head.appendChild(scriptEl);
 77→
 78→  // biome-ignore lint/suspicious/noExplicitAny: JSDOM global access requires dynamic typing
 79→  const domKit = (window as any).__domKit as
 80→    | {
 81→        elementToBlocks: (el: Element) => Array<Record<string, unknown>>;
 82→      }
 83→    | undefined;
 84→
 85→  if (!domKit) {
 86→    warnings.push("DOM kit injection failed, falling back to basic extraction");
 87→    const text = window.document.body?.textContent?.trim() ?? "";
 88→    window.close();
 89→    return createSingleMessageResult(text, platform, warnings);
 90→  }
 91→
 92→  const messages = extractMessagesFromDom(
 93→    window.document,
 94→    domKit,
 95→    platform,
 96→    warnings,
 97→  );
 98→
 99→  const title = extractTitleFromDom(window.document, platform) || "Pasted Chat";
100→
101→  window.close();
102→
103→  if (messages.length === 0) {
104→    warnings.push("No messages found in clipboard HTML");
105→    const text = html
106→      .replace(/<[^>]*>/g, " ")
107→      .replace(/\s+/g, " ")
108→      .trim();
109→    return createSingleMessageResult(text, platform, warnings);
110→  }
111→
112→  const conversation = conversationSchema.parse({
113→    id: crypto.randomUUID(),
114→    title,
115→    source: { url: "clipboard://paste", platform },
116→    messages,
117→  });
118→
119→  return { conversation, warnings, detectedPlatform: platform };
120→}
121→
122→// ---------------------------------------------------------------------------
123→// DOM message extraction
124→// ---------------------------------------------------------------------------
125→
126→function extractMessagesFromDom(
127→  document: Document,
128→  domKit: { elementToBlocks: (el: Element) => Array<Record<string, unknown>> },
129→  platform: SourcePlatform,
130→  warnings: string[],
131→): Array<{
132→  id: string;
133→  role: string;
134→  blocks: Array<Record<string, unknown>>;
135→}> {
136→  // Try platform-specific extraction
137→  const platformMessages = extractPlatformSpecific(
138→    document,
139→    domKit,
140→    platform,
141→    warnings,
142→  );
143→  if (platformMessages.length > 0) return platformMessages;
144→
145→  if (platform !== "unknown") {
146→    warnings.push(
147→      `Detected ${platform} but could not extract messages, falling back to generic extraction`,
148→    );
149→  }
150→
151→  // Generic: treat the entire body as a single assistant message
152→  return extractGeneric(document, domKit);
153→}
154→
