172→            });
173→          },
174→        }),
175→        timeoutPromise,
176→      ]);
177→    } finally {
178→      clearTimeout(timeoutHandle);
179→    }
180→
181→    withTransaction(() => {
182→      patchJob(id, {
183→        currentStage: "render",
184→        conversation: imported.conversation,
185→        summary: {
186→          messageCount: imported.conversation.messages.length,
187→          transcriptWords: conversationWordCount(imported.conversation),
188→        },
189→        warnings: imported.warnings,
