156→        reject(
157→          new Error(
158→            `Import timed out after ${IMPORT_TIMEOUT_MS / 1_000}s waiting for the share page to load.`,
159→          ),
160→        );
161→      }, IMPORT_TIMEOUT_MS);
162→    });
163→
164→    let imported: Awaited<ReturnType<typeof importSharePage>> | undefined;
165→    try {
166→      imported = await Promise.race([
167→        importSharePage(job.sourceUrl, {
168→          sourcePlatform: job.sourcePlatform,
169→          onStage: (stage) => {
170→            patchJob(id, {
171→              currentStage: stage,
172→            });
173→          },
174→        }),
175→        timeoutPromise,
176→      ]);
177→    } finally {
178→      clearTimeout(timeoutHandle);
179→    }
180→
181→    withTransaction(() => {
182→      patchJob(id, {
183→        currentStage: "render",
184→        conversation: imported.conversation,
185→        summary: {
186→          messageCount: imported.conversation.messages.length,
187→          transcriptWords: conversationWordCount(imported.conversation),
188→        },
189→        warnings: imported.warnings,
190→      });
191→
192→      saveImportSnapshot({
193→        importId: id,
194→        sourceUrl: job.sourceUrl,
195→        finalUrl: imported.snapshot.finalUrl,
196→        fetchedAt: imported.snapshot.fetchedAt,
197→        pageTitle: imported.snapshot.pageTitle,
198→        rawHtml: imported.snapshot.rawHtml,
199→        normalizedPayload: imported.snapshot.normalizedPayload,
200→        fetchMetadata: imported.snapshot.fetchMetadata,
201→      });
202→
203→      const rendered = getImportJob(id);
204→      if (!rendered) {
205→        return;
206→      }
207→
208→      patchJob(id, {
209→        status: "completed",
210→        currentStage: "done",
211→        artifacts: buildArtifacts(rendered),
212→      });
213→    });
214→  } catch (error) {
215→    const currentJob = getPersistedImport(id);
216→    patchJob(id, {
217→      status: "failed",
218→      errorStage: currentJob?.currentStage,
219→      currentStage: "done",
220→      error:
221→        error instanceof Error
222→          ? error.message
223→          : "Die Import-Pipeline ist fehlgeschlagen.",
224→    });
225→  }
226→}
