 53→function _describeSelectionLabel(selection: AdjustmentSelection) {
 54→  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
 55→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 56→  }
 57→
 58→  return formatMessageBlockLabel(
 59→    selection.messageRole,
 60→    selection.messageIndex + 1,
 61→    selection.blockType,
 62→  );
 63→}
 64→
 65→function downloadBlob(content: string, mimeType: string, filename: string) {
 66→  const blob = new Blob([content], { type: mimeType });
 67→  const url = URL.createObjectURL(blob);
 68→  const a = document.createElement("a");
 69→  a.href = url;
 70→  a.download = filename;
 71→  document.body.appendChild(a);
 72→  a.click();
 73→  document.body.removeChild(a);
 74→  setTimeout(() => URL.revokeObjectURL(url), 100);
 75→}
