 77→export function FormatWorkspace({
 78→  activeStage,
 79→  elapsedTime,
 80→  job,
 81→  view,
 82→  onViewChange,
 83→}: FormatWorkspaceProps) {
 84→  const isAdjustableView = adjustableViews.has(view);
 85→
 86→  const session = useAdjustmentSession(view, job.id);
 87→  const rules = useFormatRules(view, job.id);
 88→  const snapshots = useSnapshots(job.id);
 89→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 90→  const resolvedMessages = useResolvedConversation(
 91→    job.conversation,
 92→    messageEdits.editedMessagesMap,
 93→  );
 94→  const autoSnapshot = useAutoSnapshot({
 95→    activeSnapshot: snapshots.activeSnapshot,
 96→    create: snapshots.create,
 97→    activate: snapshots.activate,
 98→  });
 99→  const deletion = useMessageDeletion(job.id);
100→  const deletionToast = useDeletionToast();
101→  const [editMode, setEditMode] = useState<EditMode>("view");
102→
103→  // Mutual exclusion: edit mode and adjustment mode must never be active simultaneously
104→  const handleEditModeChange = useCallback(
105→    (mode: EditMode) => {
106→      if (mode === "edit" && session.adjustModeEnabled) {
107→        session.toggleAdjustMode();
108→      }
109→      setEditMode(mode);
110→    },
111→    [session],
112→  );
113→
114→  const handleToggleAdjustMode = useCallback(() => {
115→    if (!session.adjustModeEnabled && editMode === "edit") {
116→      setEditMode("view");
117→    }
118→    session.toggleAdjustMode();
119→  }, [session, editMode]);
120→
121→  const hasEdits = resolvedMessages.some((m) => m.isEdited);
122→
123→  // beforeunload warning when unsaved edits exist.
124→  // hasPendingEdits covers both debounce timers that haven't fired yet and
125→  // in-flight HTTP mutations, preventing data loss during the 500 ms debounce
126→  // window where isSaving alone would still be false.
127→  useEffect(() => {
128→    if (!messageEdits.hasPendingEdits) return;
129→    const handler = (e: BeforeUnloadEvent) => {
130→      e.preventDefault();
131→    };
132→    window.addEventListener("beforeunload", handler);
133→    return () => window.removeEventListener("beforeunload", handler);
134→  }, [messageEdits.hasPendingEdits]);
135→
136→  const handleBlocksChange = useCallback(
137→    (messageId: string, blocks: Block[]) => {
138→      void autoSnapshot.ensureSnapshot().then((snapshotId) => {
139→        if (snapshotId) {
140→          messageEdits.saveEdit(messageId, blocks, undefined, snapshotId);
141→        }
142→      });
143→    },
144→    [autoSnapshot, messageEdits],
145→  );
146→  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
147→  const [deleteDialog, setDeleteDialog] = useState<{
148→    messageId: string;
149→    isRound: boolean;
150→    preview: string;
151→  } | null>(null);
152→  const popover = useAdjustmentPopover();
153→
154→  const handleDeleteMessage = useCallback(
155→    (messageId: string) => {
156→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
157→      const preview =
158→        msg?.blocks
159→          .map((b) => ("text" in b ? b.text : b.type))
160→          .join(" ")
161→          .slice(0, 200) ?? messageId;
162→      setDeleteDialog({ messageId, isRound: false, preview });
163→    },
164→    [job.conversation?.messages],
165→  );
166→
167→  const handleDeleteRound = useCallback(
168→    (messageId: string) => {
169→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
170→      const preview =
171→        msg?.blocks
172→          .map((b) => ("text" in b ? b.text : b.type))
173→          .join(" ")
174→          .slice(0, 200) ?? messageId;
175→      setDeleteDialog({ messageId, isRound: true, preview });
176→    },
177→    [job.conversation?.messages],
178→  );
179→
180→  const handleConfirmDelete = useCallback(
181→    async (reason?: string) => {
182→      if (!deleteDialog) return;
183→      const { messageId, isRound } = deleteDialog;
184→      setDeleteDialog(null);
185→      if (isRound) {
186→        const result = await deletion.deleteRound(messageId, reason);
187→        deletionToast.showDeletedToast(messageId, true, result.length);
188→      } else {
189→        await deletion.deleteMessage(messageId, reason);
190→        deletionToast.showDeletedToast(messageId, false);
191→      }
192→    },
193→    [deleteDialog, deletion, deletionToast],
194→  );
195→
196→  const handleUndoDelete = useCallback(async () => {
197→    if (!deletionToast.toast) return;
198→    await deletion.restoreMessage(deletionToast.toast.messageId);
199→    deletionToast.dismissToast();
200→  }, [deletion, deletionToast]);
201→
202→  const mergedRef = useCallback(
203→    (node: HTMLElement | null) => {
204→      (
205→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
206→      ).current = node;
207→      (
208→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
209→      ).current = node;
210→    },
211→    [session.sectionRef, popover.containerRef],
212→  );
213→
214→  const artifact =
215→    view === "reader"
216→      ? ""
217→      : (job.artifacts?.[view] ?? "Artefakt ist noch nicht verfügbar.");
218→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
219→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
220→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
221→  const displayedMarkdown = useMemo(() => {
222→    if (view !== "markdown") return artifact;
223→    try {
224→      return applyMarkdownRules(artifact, rules.activeRules);
225→    } catch {
226→      return artifact;
227→    }
228→  }, [artifact, rules.activeRules, view]);
229→
230→  const resolvedConversation = useMemo(() => {
231→    if (!job.conversation) return undefined;
232→    return {
233→      ...job.conversation,
234→      messages: resolvedMessages.map((rm) => ({
235→        id: rm.id,
236→        role: rm.role,
237→        blocks: rm.blocks,
238→      })),
239→    };
240→  }, [job.conversation, resolvedMessages]);
241→
242→  const readerEffectsMap = useMemo(
243→    () =>
244→      view === "reader" && resolvedConversation
245→        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
246→        : new Map(),
247→    [rules.activeRules, resolvedConversation, view],
248→  );
249→
250→  const handleCopyMessage = useCallback(
251→    (messageId: string) => {
252→      const msg = resolvedConversation?.messages.find(
253→        (m) => m.id === messageId,
254→      );
255→      if (!msg) return;
256→      void copyMessageToClipboard(msg, view, msg.blocks);
257→    },
258→    [resolvedConversation, view],
259→  );
260→
261→  const [copySuccess, setCopySuccess] = useState(false);
262→  const copyTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
263→
264→  const handleCopyAll = useMemo(() => {
265→    const plugin = clientFormatRegistry.get(view);
266→    if (!plugin) return undefined;
267→
268→    const doCopy = async (content: string, isHtml: boolean) => {
269→      try {
270→        if (isHtml) {
271→          const blob = new Blob([content], { type: "text/html" });
272→          const plainBlob = new Blob([content], { type: "text/plain" });
273→          await navigator.clipboard.write([
274→            new ClipboardItem({
275→              "text/html": blob,
276→              "text/plain": plainBlob,
277→            }),
278→          ]);
279→        } else {
280→          await navigator.clipboard.writeText(content);
281→        }
282→        clearTimeout(copyTimeoutRef.current);
283→        setCopySuccess(true);
284→        copyTimeoutRef.current = setTimeout(() => setCopySuccess(false), 2000);
285→      } catch {
286→        // Fallback: silently fail
287→      }
288→    };
289→
290→    // Formats with conversation-based export (reader)
291→    if (plugin.prepareConversationExport && resolvedConversation) {
292→      const exportFn = plugin.prepareConversationExport;
293→      return () => {
294→        const html = exportFn(
295→          resolvedConversation,
296→          readerEffectsMap,
297→          resolvedConversation.title ?? `export-${job.id}`,
298→        );
299→        void doCopy(html, true);
300→      };
301→    }
302→
303→    // Markdown: displayedMarkdown already has rules applied
304→    if (view === "markdown") {
305→      return () => {
306→        void doCopy(displayedMarkdown, false);
307→      };
308→    }
309→
310→    // Others: raw artifact
311→    if (artifact) {
312→      return () => {
313→        void doCopy(artifact, false);
314→      };
315→    }
316→    return undefined;
317→  }, [
318→    view,
319→    displayedMarkdown,
320→    job.id,
321→    resolvedConversation,
322→    readerEffectsMap,
323→    artifact,
324→  ]);
325→
326→  const handleDownload = useMemo(() => {
327→    const plugin = clientFormatRegistry.get(view);
328→    if (!plugin) return undefined;
329→
330→    // Formats with conversation-based export (reader)
331→    if (plugin.prepareConversationExport && resolvedConversation) {
332→      const exportFn = plugin.prepareConversationExport;
333→      return () => {
334→        const html = exportFn(
335→          resolvedConversation,
336→          readerEffectsMap,
337→          resolvedConversation.title ?? `export-${job.id}`,
338→        );
339→        downloadBlob(
340→          html,
341→          plugin.descriptor.exportMimeType,
342→          `export-${job.id}${plugin.descriptor.exportExtension}`,
343→        );
344→      };
345→    }
346→
347→    // For all other formats: use prepareDownload if available, else raw content
348→    const content = view === "markdown" ? displayedMarkdown : artifact;
349→    if (!content) return undefined;
350→
351→    return () => {
352→      const finalContent =
353→        plugin.prepareDownload?.(content, rules.activeRules) ?? content;
354→      downloadBlob(
355→        finalContent,
356→        plugin.descriptor.exportMimeType,
357→        `export-${job.id}${plugin.descriptor.exportExtension}`,
358→      );
359→    };
360→  }, [
361→    view,
362→    displayedMarkdown,
363→    job.id,
364→    resolvedConversation,
365→    readerEffectsMap,
366→    artifact,
367→    rules.activeRules,
368→  ]);
369→  const showPopover =
370→    session.adjustModeEnabled &&
371→    Boolean(session.activeSelection) &&
372→    Boolean(session.activeAnchor);
373→
374→  const popoverCallbacksRef = useRef({
375→    handleDiscardSession: session.handleDiscardSession,
376→    activeSessionDetail: session.activeSessionDetail,
377→    handleRejectLastChange: rules.handleRejectLastChange,
378→    setReplyVisible: session.setReplyVisible,
379→  });
380→  popoverCallbacksRef.current = {
381→    handleDiscardSession: session.handleDiscardSession,
382→    activeSessionDetail: session.activeSessionDetail,
383→    handleRejectLastChange: rules.handleRejectLastChange,
384→    setReplyVisible: session.setReplyVisible,
385→  };
386→
387→  const handlePopoverClose = useCallback(() => {
388→    popoverCallbacksRef.current.handleDiscardSession();
389→  }, []);
390→
391→  const handleRejectLastChange = useCallback(() => {
392→    const {
393→      activeSessionDetail,
394→      handleRejectLastChange: reject,
395→      setReplyVisible,
396→    } = popoverCallbacksRef.current;
397→    if (activeSessionDetail) {
398→      void reject(activeSessionDetail).then((success) => {
399→        if (success) setReplyVisible(false);
400→      });
401→    }
402→  }, []);
403→
404→  const sessionError =
405→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
406→
407→  const viewErrorFallback = (_error: Error, reset: () => void) => (
408→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
409→      <p className="text-red-700">{miscLabels.viewLoadError}</p>
410→      <button
411→        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
412→        type="button"
413→        onClick={reset}
414→      >
415→        {miscLabels.retryButton}
416→      </button>
417→    </div>
418→  );
419→
420→  return (
421→    <section
422→      ref={mergedRef}
423→      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
424→    >
425→      <StatusHeader
426→        activeStage={activeStage}
427→        elapsedTime={elapsedTime}
428→        hasEdits={hasEdits}
429→        isSaving={messageEdits.isSaving}
430→        job={job}
431→      />
432→
433→      {job.status === "failed" ? (
434→        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
435→          <p className="font-medium">{miscLabels.importFailed}</p>
436→          {job.errorStage && job.errorStage !== "done" && (
437→            <p className="text-sm mt-1">
438→              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
439→            </p>
440→          )}
441→          {job.error && <p className="text-sm mt-1">{job.error}</p>}
442→        </div>
443→      ) : job.status === "queued" || job.status === "running" ? (
444→        <LoadingStateBlock stageDetail={activeStage?.detail} />
445→      ) : (
446→        <div className="space-y-4">
447→          <CompletedToolbar
448→            adjustModeEnabled={session.adjustModeEnabled}
449→            copySuccess={copySuccess}
450→            editMode={editMode}
451→            isAdjustableView={isAdjustableView}
452→            rules={rules}
453→            view={view}
454→            onCopyAll={handleCopyAll}
455→            onDownloadMarkdown={handleDownload}
456→            onEditModeChange={handleEditModeChange}
457→            onToggleAdjustMode={handleToggleAdjustMode}
458→            onViewChange={onViewChange}
459→            deletionsCount={deletion.deletionsCount}
460→            showDeleted={deletion.showDeleted}
461→            snapshotCount={snapshots.snapshots.length}
462→            onVersionsClick={() => setVersionsModalOpen(true)}
463→            onToggleShowDeleted={() =>
464→              deletion.setShowDeleted(!deletion.showDeleted)
465→            }
466→          />
467→
468→          {sessionError && !session.adjustModeEnabled ? (
469→            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
470→              {sessionError}
471→            </div>
472→          ) : null}
473→
474→          <ErrorBoundary fallback={viewErrorFallback}>
475→            {(() => {
476→              const plugin = clientFormatRegistry.get(view);
477→              if (!plugin) {
478→                return (
479→                  <div className="text-sm text-muted-foreground">
480→                    Format nicht verfügbar
481→                  </div>
482→                );
483→              }
484→              const { ViewComponent } = plugin;
485→              const viewElement = (
486→                <ViewComponent
487→                  activeRules={rules.activeRules}
488→                  conversation={resolvedConversation}
489→                  adjustModeEnabled={session.adjustModeEnabled}
490→                  editMode={editMode === "edit"}
491→                  effectsMap={readerEffectsMap}
492→                  highlightedRuleId={rules.hoveredRuleId}
493→                  selectedBlock={
494→                    view === "reader" ? session.activeSelection : null
495→                  }
496→                  onSelectBlock={session.handleSelectionChange}
497→                  deletedMessageIds={deletion.deletedMessageIds}
498→                  showDeleted={deletion.showDeleted}
499→                  onBlocksChange={handleBlocksChange}
500→                  onCopyMessage={handleCopyMessage}
501→                  onDeleteMessage={handleDeleteMessage}
502→                  onDeleteRound={handleDeleteRound}
503→                  onRestoreMessage={deletion.restoreMessage}
504→                  content={view === "markdown" ? displayedMarkdown : artifact}
505→                  selectedRange={session.activeSelection}
506→                  onSelectLines={session.handleSelectionChange}
507→                  rules={rules.activeRules}
508→                />
509→              );
510→              return viewElement;
511→            })()}
512→          </ErrorBoundary>
513→
514→          {session.showGuide ? (
515→            <AdjustmentModeGuide
516→              view={view}
517→              onDismiss={() => session.setGuideDismissed(true)}
518→            />
519→          ) : null}
520→
521→          <ErrorBoundary
522→            fallback={
523→              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
524→                {miscLabels.adjustmentLoadError}
525→              </div>
526→            }
527→          >
528→            <AdjustmentPopover
529→              anchor={session.activeAnchor ?? null}
530→              containerRef={session.sectionRef}
531→              draftMessage={session.activeDraftMessage}
532→              error={session.activeSessionError}
533→              isLoading={session.activeSessionLoading || session.isDiscarding}
534→              isSubmitting={session.isSubmitting}
535→              open={
536→                showPopover &&
537→                Boolean(session.activeSelection) &&
538→                Boolean(session.activeAnchor)
539→              }
540→              sessionDetail={session.activeSessionDetail}
541→              showReply={session.replyVisible}
542→              view={view}
543→              onClose={handlePopoverClose}
544→              onDraftMessageChange={session.handleDraftMessageChange}
545→              onRejectLastChange={handleRejectLastChange}
546→              onSubmitMessage={session.handleSubmitMessage}
547→            />
548→          </ErrorBoundary>
549→        </div>
550→      )}
551→
552→      {deleteDialog && (
553→        <DeleteMessageDialog
554→          messagePreview={deleteDialog.preview}
555→          isRound={deleteDialog.isRound}
556→          onConfirm={(reason) => {
557→            void handleConfirmDelete(reason);
558→          }}
559→          onCancel={() => setDeleteDialog(null)}
560→        />
561→      )}
562→
563→      {deletionToast.toast && (
564→        <UndoToast
565→          message={deletionToast.toast.message}
566→          onUndo={() => {
567→            void handleUndoDelete();
568→          }}
569→          onDismiss={deletionToast.dismissToast}
570→        />
571→      )}
572→
573→      <VersionsModal
574→        open={versionsModalOpen}
575→        onOpenChange={setVersionsModalOpen}
576→        snapshots={snapshots.snapshots}
577→        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
578→        onActivate={(snapshotId) => {
579→          void snapshots.activate(snapshotId);
580→        }}
581→        onDeactivate={() => {
582→          void snapshots.deactivate();
583→        }}
584→        onCreate={(label) => {
585→          void snapshots.create(label);
586→        }}
587→        onRename={(snapshotId, label) => {
588→          void snapshots.rename(snapshotId, label);
589→        }}
590→        onDelete={(snapshotId) => {
591→          void snapshots.delete(snapshotId);
592→        }}
593→      />
594→    </section>
595→  );
596→}
