191→function buildSelectorSchema(targetFormat: AdjustmentTargetFormat = "reader") {
192→  const isMarkdown = targetFormat === "markdown";
193→
194→  // For Markdown, compound selectors only support textPattern (line-based matching).
195→  // blockType, messageRole, headingLevel, position, and context are block/message
196→  // concepts that do not exist in the flat line-based Markdown representation and
197→  // are silently ignored by applyMarkdownRules. Exposing them would mislead the AI
198→  // into generating selectors that appear meaningful but have no effect.
199→  const compoundProperties = isMarkdown
200→    ? {
201→        textPattern: {
202→          type: "string",
203→          description:
204→            "Nur für compound: Regex-Pattern das im Markdown-Text matchen muss.",
205→        },
206→      }
207→    : {
208→        messageRole: {
209→          type: "string",
