415→function blockToPlainText(block: Block) {
416→  switch (block.type) {
417→    case "paragraph":
418→    case "heading":
419→    case "quote":
420→    case "code":
421→      return block.text;
422→    case "list":
423→      return block.items.join("\n");
424→    case "table":
425→      return [
426→        block.headers.join(" | "),
427→        ...block.rows.map((row) => row.join(" | ")),
428→      ].join("\n");
429→  }
430→}
431→
432→function summarizeSelection(
433→  sessionDetail: AdjustmentSessionDetail,
434→  job: ImportJob | undefined,
435→) {
436→  const { selection, targetFormat } = sessionDetail.session;
437→
438→  if (targetFormat === "markdown") {
439→    const markdown = job?.artifacts?.markdown ?? "";
440→    const lines = markdown.split("\n");
441→    const lineStart = selection.lineStart ?? 1;
442→    const lineEnd = selection.lineEnd ?? lineStart;
443→
444→    return {
445→      currentExcerpt:
446→        lines.slice(lineStart - 1, lineEnd).join("\n") ||
447→        selection.selectedText,
448→      description: `Markdown-Zeilen ${lineStart}-${lineEnd}`,
449→      surrounding: {
450→        next: lines[lineEnd] ?? null,
451→        previous: lineStart > 1 ? (lines[lineStart - 2] ?? null) : null,
452→      },
453→    };
454→  }
455→
456→  const message = job?.conversation?.messages.find(
457→    (entry) => entry.id === selection.messageId,
458→  );
459→  const currentBlock = message?.blocks[selection.blockIndex];
460→  const previousBlock =
461→    selection.blockIndex > 0
462→      ? message?.blocks[selection.blockIndex - 1]
463→      : undefined;
464→  const nextBlock = message?.blocks[selection.blockIndex + 1];
465→
466→  return {
467→    currentExcerpt: currentBlock
468→      ? blockToPlainText(currentBlock)
469→      : selection.selectedText,
470→    description: `${selection.messageRole} message ${selection.messageIndex + 1}, ${selection.blockType}`,
471→    surrounding: {
472→      next: nextBlock ? blockToPlainText(nextBlock) : null,
473→      previous: previousBlock ? blockToPlainText(previousBlock) : null,
474→    },
475→  };
476→}
477→
478→function buildSelectionContext(input: RunAgentTurnInput) {
479→  const { activeRules, job, sessionDetail } = input;
480→  const { selection, targetFormat } = sessionDetail.session;
481→  const selectionContext = summarizeSelection(sessionDetail, job);
482→  const lines: string[] = [];
483→
484→  lines.push("## Ausgewählter Block");
485→  lines.push(`Format: ${targetFormat}`);
486→  lines.push(
487→    `Block: ${selection.blockType} (messageId: "${selection.messageId}", blockId: "${selection.blockId ?? ""}", blockIndex: ${selection.blockIndex})`,
488→  );
489→  lines.push(
490→    `Rolle: ${selection.messageRole}, Nachricht ${selection.messageIndex + 1}`,
491→  );
492→  if (selection.lineStart != null) {
493→    lines.push(
494→      `Zeilen: ${selection.lineStart}-${selection.lineEnd ?? selection.lineStart}`,
495→    );
496→  }
497→  lines.push("");
498→  lines.push("Inhalt des ausgewählten Blocks:");
499→  lines.push("```");
500→  lines.push(selectionContext.currentExcerpt);
501→  lines.push("```");
502→
503→  if (selectionContext.surrounding.previous) {
504→    lines.push("");
505→    lines.push("Block davor:");
506→    lines.push(`> ${selectionContext.surrounding.previous.slice(0, 200)}`);
507→  }
508→  if (selectionContext.surrounding.next) {
509→    lines.push("");
510→    lines.push("Block danach:");
511→    lines.push(`> ${selectionContext.surrounding.next.slice(0, 200)}`);
512→  }
513→
514→  const active = activeRules
515→    .filter((rule) => rule.status === "active")
516→    .slice(0, 8);
517→  if (active.length > 0) {
518→    lines.push("");
519→    lines.push("## Bereits aktive Regeln");
520→    for (const rule of active) {
521→      const selectorStr = rule.selector
522→        ? JSON.stringify(rule.selector)
523→        : "(kein Selektor)";
524→      lines.push(
525→        `- [${rule.id}] ${rule.instruction ?? "(keine Beschreibung)"} — Selektor: ${selectorStr}`,
526→      );
527→    }
528→  }
529→
530→  return lines.join("\n");
531→}
