533→type InputMessage = {
534→  content: Array<{ text: string; type: "input_text" | "output_text" }>;
535→  role: "system" | "user" | "assistant";
536→};
537→
538→function buildInputMessages(input: RunAgentTurnInput): InputMessage[] {
539→  const targetFormat = input.sessionDetail.session.targetFormat;
540→  const messages: InputMessage[] = [
541→    {
542→      content: [{ text: buildSystemPrompt(targetFormat), type: "input_text" }],
543→      role: "system",
544→    },
545→    {
546→      content: [{ text: buildSelectionContext(input), type: "input_text" }],
547→      role: "user",
548→    },
549→  ];
550→
551→  // Add session messages as real multi-turn conversation so the model
552→  // understands the full dialog history and can reference prior turns.
553→  for (const msg of input.sessionDetail.messages) {
554→    const role = msg.role === "user" ? "user" : "assistant";
555→    messages.push({
556→      content: [
557→        {
558→          text: msg.content,
559→          type: role === "assistant" ? "output_text" : "input_text",
560→        },
561→      ],
562→      role,
563→    });
564→  }
565→
566→  return messages;
567→}
