569→// ---------------------------------------------------------------------------
570→// OpenAI helpers
571→// ---------------------------------------------------------------------------
572→
573→function isRecord(value: unknown): value is Record<string, unknown> {
574→  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
575→}
576→
577→function extractFunctionCalls(payload: ResponsesPayload): FunctionCallItem[] {
578→  if (!Array.isArray(payload.output)) {
579→    return [];
580→  }
581→
582→  return payload.output.flatMap((item) => {
583→    if (!isRecord(item) || item.type !== "function_call") {
584→      return [];
585→    }
586→
587→    const callId = typeof item.call_id === "string" ? item.call_id : null;
588→    const name = typeof item.name === "string" ? item.name : null;
589→    const args = typeof item.arguments === "string" ? item.arguments : null;
590→
591→    if (!callId || !name || !args) {
592→      return [];
593→    }
594→
595→    return [{ arguments: args, callId, name }];
596→  });
597→}
598→
599→function extractAssistantMessage(payload: ResponsesPayload) {
600→  if (typeof payload.output_text === "string" && payload.output_text.trim()) {
601→    return payload.output_text.trim();
602→  }
603→
604→  if (!Array.isArray(payload.output)) {
605→    return "";
606→  }
607→
608→  return payload.output
609→    .flatMap((item) => {
610→      if (
611→        !isRecord(item) ||
612→        item.type !== "message" ||
613→        item.role !== "assistant"
614→      ) {
615→        return [];
616→      }
617→
618→      const content = item.content;
619→      if (!Array.isArray(content)) {
620→        return [];
621→      }
622→
623→      return content.flatMap((entry) => {
624→        if (!isRecord(entry) || entry.type !== "output_text") {
625→          return [];
626→        }
627→
628→        return typeof entry.text === "string" && entry.text.trim()
629→          ? [entry.text.trim()]
630→          : [];
631→      });
632→    })
633→    .join("\n")
634→    .trim();
635→}
