666→// ---------------------------------------------------------------------------
667→// Tool execution with validation
668→// ---------------------------------------------------------------------------
669→
670→function validateEffect(effect: unknown): {
671→  ok: boolean;
672→  data?: Record<string, unknown>;
673→  error?: string;
674→} {
675→  const result = customStyleEffectSchema.safeParse(effect);
676→  if (result.success) {
677→    return { ok: true, data: result.data as Record<string, unknown> };
678→  }
679→
680→  const issues = result.error.issues
681→    .map((i) => `${i.path.join(".")}: ${i.message}`)
682→    .join("; ");
683→  return { ok: false, error: `Effect-Validierung fehlgeschlagen: ${issues}` };
684→}
685→
686→async function executeToolCall(
687→  call: FunctionCallItem,
688→  callbacks: RunAgentTurnInput["callbacks"],
689→  actions: ActionRecord[],
690→): Promise<string> {
691→  let args: Record<string, unknown>;
692→  try {
693→    args = JSON.parse(call.arguments) as Record<string, unknown>;
694→  } catch {
695→    return JSON.stringify({
696→      ok: false,
697→      error: `Ungültige Tool-Argumente: ${call.arguments}`,
698→    });
699→  }
700→
701→  if (call.name === "create_rule") {
702→    const effectValidation = validateEffect(args.effect);
703→    if (!effectValidation.ok) {
704→      return JSON.stringify({ ok: false, error: effectValidation.error });
705→    }
706→
707→    try {
708→      const { ruleId } = await callbacks.onCreateRule({
709→        selector: args.selector as Record<string, unknown>,
710→        effect: effectValidation.data as Record<string, unknown>,
711→        description: String(args.description ?? ""),
712→      });
713→      actions.push({ type: "created", ruleId });
714→      return JSON.stringify({ ok: true, ruleId });
715→    } catch (error) {
716→      return JSON.stringify({
717→        ok: false,
718→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
719→      });
720→    }
721→  }
722→
723→  if (call.name === "update_rule") {
724→    const effectValidation = validateEffect(args.effect);
725→    if (!effectValidation.ok) {
726→      return JSON.stringify({ ok: false, error: effectValidation.error });
727→    }
728→
729→    const ruleId = String(args.ruleId ?? "");
730→
731→    try {
732→      await callbacks.onUpdateRule({
733→        ruleId,
734→        effect: effectValidation.data as Record<string, unknown>,
735→        description:
736→          typeof args.description === "string" ? args.description : undefined,
737→      });
738→      actions.push({ type: "updated", ruleId });
739→      return JSON.stringify({ ok: true, ruleId });
740→    } catch (error) {
741→      return JSON.stringify({
742→        ok: false,
743→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
744→      });
745→    }
746→  }
747→
748→  if (call.name === "delete_rule") {
749→    const ruleId = String(args.ruleId ?? "");
750→
751→    try {
752→      await callbacks.onDeleteRule(ruleId);
753→      actions.push({ type: "deleted", ruleId });
754→      return JSON.stringify({ ok: true, ruleId });
755→    } catch (error) {
756→      return JSON.stringify({
757→        ok: false,
758→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
759→      });
760→    }
761→  }
762→
763→  return JSON.stringify({
764→    ok: false,
765→    error: `Unbekannter Tool-Call: ${call.name}`,
766→  });
767→}
