769→// ---------------------------------------------------------------------------
770→// Main agent turn
771→// ---------------------------------------------------------------------------
772→
773→export async function runAgentTurn(input: RunAgentTurnInput): Promise<{
774→  assistantMessage: string;
775→  actions: ActionRecord[];
776→}> {
777→  const config = readAdjustmentAiConfig();
778→
779→  if (!config.enabled || config.provider !== "openai" || !config.openai) {
780→    throw new AgentUnavailableError(
781→      "Live-KI-Anpassungen sind aktuell nicht konfiguriert. Hinterlege einen OpenAI-Zugang, bevor du diesen Chat nutzt.",
782→    );
783→  }
784→
785→  const actions: ActionRecord[] = [];
786→  const targetFormat = input.sessionDetail.session.targetFormat;
787→
788→  const inputMessages = buildInputMessages(input);
789→
790→  let payload = await requestOpenAiResponse(
791→    {
792→      input: inputMessages,
793→      tool_choice: "auto",
794→      tools: buildTools(targetFormat),
795→    },
796→    config,
797→  );
798→
799→  for (let round = 0; round < MAX_TOOL_ROUNDS; round += 1) {
800→    const functionCalls = extractFunctionCalls(payload);
801→    if (functionCalls.length === 0) {
802→      break;
803→    }
804→
805→    if (!payload.id) {
806→      throw new Error(
807→        "Die KI-Antwort enthält keine Response-ID für den Tool-Loop.",
808→      );
809→    }
810→
811→    const toolOutputs = [];
812→
813→    for (const call of functionCalls) {
814→      const result = await executeToolCall(call, input.callbacks, actions);
815→      toolOutputs.push({
816→        type: "function_call_output",
817→        call_id: call.callId,
818→        output: result,
819→      });
820→    }
821→
822→    payload = await requestOpenAiResponse(
823→      {
824→        input: toolOutputs,
825→        previous_response_id: payload.id,
826→        tool_choice: "auto",
827→        tools: buildTools(targetFormat),
828→      },
829→      config,
830→    );
831→  }
832→
833→  const rawMessage = extractAssistantMessage(payload);
834→  let assistantMessage: string;
835→
836→  if (rawMessage) {
837→    assistantMessage = rawMessage;
838→  } else if (actions.length > 0) {
839→    assistantMessage = "Die Änderung ist jetzt sichtbar.";
840→  } else {
841→    // The AI returned no text and took no actions — retry once with an
842→    // explicit nudge so the user sees an actual question instead of a
843→    // generic placeholder.
844→    const retryPayload = await requestOpenAiResponse(
845→      {
846→        input: [
847→          ...inputMessages,
848→          {
849→            content: [
850→              {
851→                text: "Du hast gerade keine Antwort gegeben. Bitte stelle dem Nutzer jetzt eine konkrete Rückfrage, damit du eine passende Regel erstellen kannst.",
852→                type: "input_text",
853→              },
854→            ],
855→            role: "user",
856→          },
857→        ],
858→        tool_choice: "none",
859→        tools: buildTools(targetFormat),
860→      },
861→      config,
862→    );
863→
864→    assistantMessage =
865→      extractAssistantMessage(retryPayload) ||
866→      "Ich konnte die Anfrage nicht verstehen. Kannst du bitte genauer beschreiben, was du ändern möchtest?";
867→  }
868→
869→  return { assistantMessage, actions };
870→}
