import type {
  Conversation,
  ImportArtifacts,
  ImportJob,
  ImportListRequest,
  ImportSummary,
} from "@chat-exporter/shared";
import { importJobSchema, importSummarySchema } from "@chat-exporter/shared";
import { and, asc, desc, eq, like, or } from "drizzle-orm";

import { db } from "../db/client.js";
import type { Import } from "../db/schema.js";
import { importSnapshots, imports } from "../db/schema.js";

function serializeImport(job: ImportJob) {
  return {
    id: job.id,
    sourceUrl: job.sourceUrl,
    sourcePlatform: job.sourcePlatform,
    mode: job.mode,
    status: job.status,
    currentStage: job.currentStage,
    createdAt: job.createdAt,
    updatedAt: job.updatedAt,
    warningsJson: JSON.stringify(job.warnings),
    error: job.error ?? null,
    errorStage: job.errorStage ?? null,
    summaryJson: job.summary ? JSON.stringify(job.summary) : null,
    conversationJson: job.conversation
      ? JSON.stringify(job.conversation)
      : null,
    artifactsJson: job.artifacts ? JSON.stringify(job.artifacts) : null,
  };
}

function parseJson<T>(value: string | null): T | undefined {
  if (!value) {
    return undefined;
  }

  return JSON.parse(value) as T;
}

function deserializeImport(row: Import) {
  return importJobSchema.parse({
    id: row.id,
    sourceUrl: row.sourceUrl,
    sourcePlatform: row.sourcePlatform,
    mode: row.mode,
    status: row.status,
    currentStage: row.currentStage,
    createdAt: row.createdAt,
    updatedAt: row.updatedAt,
    warnings: parseJson<string[]>(row.warningsJson) ?? [],
    error: row.error ?? undefined,
    errorStage: row.errorStage ?? undefined,
    summary: parseJson<ImportJob["summary"]>(row.summaryJson),
    conversation: parseJson<Conversation>(row.conversationJson),
    artifacts: parseJson<ImportArtifacts>(row.artifactsJson),
  });
}

export function insertImport(job: ImportJob) {
  db.insert(imports).values(serializeImport(job)).run();
}

export function replaceImport(job: ImportJob) {
  const data = serializeImport(job);
  const { id: _id, ...fields } = data;
  db.update(imports).set(fields).where(eq(imports.id, job.id)).run();

import {
  index,
  integer,
  sqliteTable,
  text,
  uniqueIndex,
} from "drizzle-orm/sqlite-core";

export const imports = sqliteTable(
  "imports",
  {
    id: text("id").primaryKey(),
    sourceUrl: text("source_url").notNull(),
    sourcePlatform: text("source_platform").notNull(),
    mode: text("mode").notNull(),
    status: text("status").notNull(),
    currentStage: text("current_stage").notNull(),
    createdAt: text("created_at").notNull(),
    updatedAt: text("updated_at").notNull(),
    warningsJson: text("warnings_json").notNull().default("[]"),
    error: text("error"),
    errorStage: text("error_stage"),
    summaryJson: text("summary_json"),
    conversationJson: text("conversation_json"),
    artifactsJson: text("artifacts_json"),
  },
  (table) => [
    index("idx_imports_created_at").on(table.createdAt),
    index("idx_imports_status").on(table.status),
  ],
);

export const importSnapshots = sqliteTable("import_snapshots", {
  importId: text("import_id")
    .primaryKey()
    .references(() => imports.id, { onDelete: "cascade" }),
  sourceUrl: text("source_url").notNull(),
  finalUrl: text("final_url").notNull(),
  fetchedAt: text("fetched_at").notNull(),
  pageTitle: text("page_title").notNull(),
  rawHtml: text("raw_html").notNull(),
  normalizedPayloadJson: text("normalized_payload_json").notNull(),
  fetchMetadataJson: text("fetch_metadata_json").notNull(),
  updatedAt: text("updated_at").notNull(),
});

export const adjustmentSessions = sqliteTable(
  "adjustment_sessions",
  {
    id: text("id").primaryKey(),
    importId: text("import_id")
      .notNull()
      .references(() => imports.id, { onDelete: "cascade" }),
    targetFormat: text("target_format").notNull(),
    status: text("status").notNull(),
    selectionJson: text("selection_json").notNull(),
    previewArtifactJson: text("preview_artifact_json"),
    createdAt: text("created_at").notNull(),
    updatedAt: text("updated_at").notNull(),
  },
  (table) => [
    index("idx_adjustment_sessions_import_id").on(
      table.importId,
      table.createdAt,
    ),
    index("idx_adjustment_sessions_target_format").on(
      table.targetFormat,
      table.updatedAt,
    ),
  ],
);

export const adjustmentMessages = sqliteTable(
  "adjustment_messages",
  {
    id: text("id").primaryKey(),
