  1→import {
  2→  type Conversation,
  3→  conversationSchema,
  4→  type SourcePlatform,
  5→} from "@chat-exporter/shared";
  6→import { JSDOM } from "jsdom";
  7→import { DOM_KIT_SCRIPT } from "./parser-dom-kit.js";
  8→
  9→export type ClipboardImportResult = {
 10→  conversation: Conversation;
 11→  warnings: string[];
 12→  detectedPlatform: SourcePlatform;
 13→};
 14→
 15→/**
 16→ * Import a conversation from clipboard content (HTML and/or plain text).
 17→ * No browser required — uses JSDOM for HTML parsing.
 18→ */
 19→export async function importFromClipboard(input: {
 20→  html?: string;
 21→  plainText?: string;
 22→}): Promise<ClipboardImportResult> {
 23→  const warnings: string[] = [];
 24→
 25→  if (input.html) {
 26→    return importFromClipboardHtml(input.html, warnings);
 27→  }
 28→
 29→  if (input.plainText) {
 30→    return importFromClipboardText(input.plainText, warnings);
 31→  }
 32→
 33→  throw new Error("Either html or plainText must be provided");
 34→}
 35→
 36→// ---------------------------------------------------------------------------
 37→// Platform detection
 38→// ---------------------------------------------------------------------------
 39→
 40→export function detectPlatformFromHtml(html: string): SourcePlatform {
 41→  const lower = html.toLowerCase();
 42→
 43→  if (lower.includes("data-message-author-role")) return "chatgpt";
 44→  if (lower.includes("font-claude-message") || lower.includes("claude.ai"))
 45→    return "claude";
 46→  if (lower.includes("share-turn-viewer") || lower.includes("gemini"))
 47→    return "gemini";
 48→  if (lower.includes("grok")) return "grok";
 49→  if (lower.includes("deepseek")) return "deepseek";
 50→  if (lower.includes("perplexity")) return "perplexity";
 51→  if (lower.includes("mistral") || lower.includes("lechat")) return "lechat";
 52→
 53→  return "unknown";
 54→}
 55→
 56→// ---------------------------------------------------------------------------
 57→// HTML path
 58→// ---------------------------------------------------------------------------
 59→
 60→function importFromClipboardHtml(
 61→  html: string,
 62→  warnings: string[],
 63→): ClipboardImportResult {
 64→  const platform = detectPlatformFromHtml(html);
 65→
 66→  if (platform === "unknown") {
 67→    warnings.push("Could not detect platform from clipboard HTML");
 68→  }
 69→
 70→  const dom = new JSDOM(html, { runScripts: "dangerously" });
 71→  const { window } = dom;
 72→
 73→  // Inject DOM kit script into JSDOM
 74→  const scriptEl = window.document.createElement("script");
 75→  scriptEl.textContent = DOM_KIT_SCRIPT;
 76→  window.document.head.appendChild(scriptEl);
 77→
 78→  // biome-ignore lint/suspicious/noExplicitAny: JSDOM global access requires dynamic typing
 79→  const domKit = (window as any).__domKit as
 80→    | {
 81→        elementToBlocks: (el: Element) => Array<Record<string, unknown>>;
 82→      }
 83→    | undefined;
 84→
 85→  if (!domKit) {
 86→    warnings.push("DOM kit injection failed, falling back to basic extraction");
 87→    const text = window.document.body?.textContent?.trim() ?? "";
 88→    window.close();
 89→    return createSingleMessageResult(text, platform, warnings);
 90→  }
 91→
 92→  const messages = extractMessagesFromDom(
 93→    window.document,
 94→    domKit,
 95→    platform,
 96→    warnings,
 97→  );
 98→
 99→  const title = extractTitleFromDom(window.document, platform) || "Pasted Chat";
100→
101→  window.close();
102→
103→  if (messages.length === 0) {
104→    warnings.push("No messages found in clipboard HTML");
105→    const text = html
106→      .replace(/<[^>]*>/g, " ")
107→      .replace(/\s+/g, " ")
108→      .trim();
109→    return createSingleMessageResult(text, platform, warnings);
110→  }
111→
112→  const conversation = conversationSchema.parse({
113→    id: crypto.randomUUID(),
114→    title,
115→    source: { url: "clipboard://paste", platform },
116→    messages,
117→  });
118→
119→  return { conversation, warnings, detectedPlatform: platform };
120→}
121→
122→// ---------------------------------------------------------------------------
123→// DOM message extraction
124→// ---------------------------------------------------------------------------
125→
126→function extractMessagesFromDom(
127→  document: Document,
128→  domKit: { elementToBlocks: (el: Element) => Array<Record<string, unknown>> },
129→  platform: SourcePlatform,
130→  warnings: string[],
131→): Array<{
132→  id: string;
133→  role: string;
134→  blocks: Array<Record<string, unknown>>;
135→}> {
136→  // Try platform-specific extraction
137→  const platformMessages = extractPlatformSpecific(
138→    document,
139→    domKit,
140→    platform,
141→    warnings,
142→  );
143→  if (platformMessages.length > 0) return platformMessages;
144→
145→  if (platform !== "unknown") {
146→    warnings.push(
147→      `Detected ${platform} but could not extract messages, falling back to generic extraction`,
148→    );
149→  }
150→
151→  // Generic: treat the entire body as a single assistant message
152→  return extractGeneric(document, domKit);
153→}
154→
155→function extractPlatformSpecific(
156→  document: Document,
157→  domKit: { elementToBlocks: (el: Element) => Array<Record<string, unknown>> },
158→  platform: SourcePlatform,
159→  _warnings: string[],
160→): Array<{
161→  id: string;
162→  role: string;
163→  blocks: Array<Record<string, unknown>>;
164→}> {
165→  const messages: Array<{
166→    id: string;
167→    role: string;
168→    blocks: Array<Record<string, unknown>>;
169→  }> = [];
170→
171→  if (platform === "chatgpt") {
172→    // ChatGPT uses data-message-author-role attribute
173→    const turns = document.querySelectorAll("[data-message-author-role]");
174→    for (const turn of turns) {
175→      const role =
176→        turn.getAttribute("data-message-author-role") === "user"
177→          ? "user"
178→          : "assistant";
179→      const blocks = domKit.elementToBlocks(turn as Element);
180→      if (blocks.length > 0) {
181→        messages.push({ id: crypto.randomUUID(), role, blocks });
182→      }
183→    }
184→  }
185→
186→  // Additional platform-specific selectors can be added here
187→
188→  return messages;
189→}
190→
191→function extractGeneric(
192→  document: Document,
193→  domKit: { elementToBlocks: (el: Element) => Array<Record<string, unknown>> },
194→): Array<{
195→  id: string;
196→  role: string;
197→  blocks: Array<Record<string, unknown>>;
198→}> {
199→  const body = document.body;
200→  if (!body) return [];
201→
202→  const blocks = domKit.elementToBlocks(body);
203→  if (blocks.length === 0) return [];
204→
205→  return [
206→    {
207→      id: crypto.randomUUID(),
208→      role: "unknown",
209→      blocks,
210→    },
211→  ];
212→}
213→
214→function extractTitleFromDom(
215→  document: Document,
216→  _platform: SourcePlatform,
217→): string | null {
218→  // Try <title> first
219→  const title = document.querySelector("title")?.textContent?.trim();
220→  if (title) return title;
221→
222→  // Try first <h1>
223→  const h1 = document.querySelector("h1")?.textContent?.trim();
224→  if (h1) return h1;
225→
226→  return null;
227→}
228→
229→// ---------------------------------------------------------------------------
230→// Plain-text path
231→// ---------------------------------------------------------------------------
232→
233→const ROLE_HEADERS: Record<string, "user" | "assistant"> = {
234→  you: "user",
235→  user: "user",
236→  human: "user",
237→  claude: "assistant",
238→  chatgpt: "assistant",
239→  assistant: "assistant",
240→  grok: "assistant",
241→  gemini: "assistant",
242→  deepseek: "assistant",
243→  perplexity: "assistant",
244→};
245→
246→const PLATFORM_FROM_HEADER: Record<string, SourcePlatform> = {
247→  claude: "claude",
248→  chatgpt: "chatgpt",
249→  grok: "grok",
250→  gemini: "gemini",
251→  deepseek: "deepseek",
252→  perplexity: "perplexity",
253→};
254→
255→function importFromClipboardText(
256→  text: string,
257→  warnings: string[],
258→): ClipboardImportResult {
259→  const lines = text.split("\n");
260→  const messages: Array<{
261→    id: string;
262→    role: string;
263→    blocks: Array<{ type: string; text: string }>;
264→  }> = [];
265→  let currentRole: "user" | "assistant" | null = null;
266→  let currentContent: string[] = [];
267→  let detectedPlatform: SourcePlatform = "unknown";
268→
269→  for (const line of lines) {
270→    const trimmed = line.trim();
271→    const normalizedHeader = trimmed.toLowerCase().replace(/:$/, "");
272→    const headerRole = ROLE_HEADERS[normalizedHeader];
273→
274→    if (headerRole) {
275→      // Flush previous message
276→      if (currentRole && currentContent.length > 0) {
277→        const content = currentContent.join("\n").trim();
278→        if (content) {
279→          messages.push({
280→            id: crypto.randomUUID(),
281→            role: currentRole,
282→            blocks: [{ type: "paragraph", text: content }],
283→          });
284→        }
285→      }
286→      currentRole = headerRole;
287→      currentContent = [];
288→
289→      // Detect platform from header
290→      if (
291→        detectedPlatform === "unknown" &&
292→        PLATFORM_FROM_HEADER[normalizedHeader]
293→      ) {
294→        detectedPlatform = PLATFORM_FROM_HEADER[normalizedHeader];
295→      }
296→    } else {
297→      currentContent.push(line);
298→    }
299→  }
300→
301→  // Flush last message
302→  if (currentRole && currentContent.length > 0) {
303→    const content = currentContent.join("\n").trim();
304→    if (content) {
305→      messages.push({
306→        id: crypto.randomUUID(),
307→        role: currentRole,
308→        blocks: [{ type: "paragraph", text: content }],
309→      });
310→    }
311→  }
312→
313→  if (messages.length === 0) {
314→    warnings.push(
315→      "No role headers found in plain text. Creating single message.",
316→    );
317→    messages.push({
318→      id: crypto.randomUUID(),
319→      role: "unknown",
320→      blocks: [{ type: "paragraph", text: text.trim() }],
321→    });
322→  }
323→
324→  warnings.push("Imported from plain text — formatting may be lost.");
325→
326→  const conversation = conversationSchema.parse({
327→    id: crypto.randomUUID(),
328→    title: "Pasted Chat",
329→    source: { url: "clipboard://paste", platform: detectedPlatform },
330→    messages,
331→  });
332→
333→  return {
334→    conversation,
335→    warnings,
336→    detectedPlatform,
337→  };
338→}
339→
340→// ---------------------------------------------------------------------------
341→// Helpers
342→// ---------------------------------------------------------------------------
343→
344→function createSingleMessageResult(
345→  text: string,
346→  platform: SourcePlatform,
347→  warnings: string[],
348→): ClipboardImportResult {
349→  const conversation = conversationSchema.parse({
350→    id: crypto.randomUUID(),
351→    title: "Pasted Chat",
352→    source: { url: "clipboard://paste", platform },
353→    messages: [
354→      {
355→        id: crypto.randomUUID(),
356→        role: "unknown",
357→        blocks: text ? [{ type: "paragraph", text }] : [],
358→      },
359→    ],
360→  });
361→
362→  return { conversation, warnings, detectedPlatform: platform };
363→}
