 1→import type { Conversation } from "@chat-exporter/shared";
 2→import {
 3→  conversationToHandover,
 4→  conversationToMarkdown,
 5→} from "./conversation-artifacts.js";
 6→
 7→export interface ArtifactGenerator {
 8→  formatId: string;
 9→  generate(conversation: Conversation): string;
10→}
11→
12→export const markdownGenerator: ArtifactGenerator = {
13→  formatId: "markdown",
14→  generate: conversationToMarkdown,
15→};
16→
17→export const handoverGenerator: ArtifactGenerator = {
18→  formatId: "handover",
19→  generate: conversationToHandover,
20→};
21→
22→export const jsonGenerator: ArtifactGenerator = {
23→  formatId: "json",
24→  generate: (conversation) => JSON.stringify(conversation, null, 2),
25→};
26→
27→export class ArtifactGeneratorRegistry {
28→  private generators = new Map<string, ArtifactGenerator>();
29→
30→  register(generator: ArtifactGenerator): void {
31→    this.generators.set(generator.formatId, generator);
32→  }
33→
34→  generate(formatId: string, conversation: Conversation): string {
35→    const generator = this.generators.get(formatId);
36→    if (!generator) {
37→      throw new Error(
38→        `No artifact generator registered for format "${formatId}"`,
39→      );
40→    }
41→    return generator.generate(conversation);
42→  }
43→
44→  getAll(): ArtifactGenerator[] {
45→    return [...this.generators.values()];
46→  }
47→}
48→

  1→import type { Conversation } from "@chat-exporter/shared";
  2→import { describe, expect, test } from "vitest";
  3→import {
  4→  type ArtifactGenerator,
  5→  ArtifactGeneratorRegistry,
  6→  handoverGenerator,
  7→  jsonGenerator,
  8→  markdownGenerator,
  9→} from "./artifact-generators.js";
 10→import {
 11→  conversationToHandover,
 12→  conversationToMarkdown,
 13→} from "./conversation-artifacts.js";
 14→
 15→function createConversation(
 16→  overrides: Partial<Conversation> = {},
 17→): Conversation {
 18→  return {
 19→    id: "conv-1",
 20→    title: "Test Conversation",
 21→    source: { url: "https://chatgpt.com/share/abc", platform: "chatgpt" },
 22→    messages: [
 23→      {
 24→        id: "msg-1",
 25→        role: "user",
 26→        blocks: [{ id: "b1", type: "paragraph", text: "Hello" }],
 27→      },
 28→      {
 29→        id: "msg-2",
 30→        role: "assistant",
 31→        blocks: [
 32→          { id: "b2", type: "paragraph", text: "Hi there" },
 33→          {
 34→            id: "b3",
 35→            type: "code",
 36→            language: "typescript",
 37→            text: "const x = 1;",
 38→          },
 39→        ],
 40→      },
 41→    ],
 42→    ...overrides,
 43→  };
 44→}
 45→
 46→describe("ArtifactGenerator implementations", () => {
 47→  const conversation = createConversation();
 48→
 49→  test("markdownGenerator produces identical output to conversationToMarkdown", () => {
 50→    const expected = conversationToMarkdown(conversation);
 51→    const actual = markdownGenerator.generate(conversation);
 52→    expect(actual).toBe(expected);
 53→  });
 54→
 55→  test("markdownGenerator has formatId 'markdown'", () => {
 56→    expect(markdownGenerator.formatId).toBe("markdown");
 57→  });
 58→
 59→  test("handoverGenerator produces identical output to conversationToHandover", () => {
 60→    const expected = conversationToHandover(conversation);
 61→    const actual = handoverGenerator.generate(conversation);
 62→    expect(actual).toBe(expected);
 63→  });
 64→
 65→  test("handoverGenerator has formatId 'handover'", () => {
 66→    expect(handoverGenerator.formatId).toBe("handover");
 67→  });
 68→
 69→  test("jsonGenerator produces pretty-printed JSON of the conversation", () => {
 70→    const expected = JSON.stringify(conversation, null, 2);
 71→    const actual = jsonGenerator.generate(conversation);
 72→    expect(actual).toBe(expected);
 73→  });
 74→
 75→  test("jsonGenerator has formatId 'json'", () => {
 76→    expect(jsonGenerator.formatId).toBe("json");
 77→  });
 78→});
 79→
 80→describe("ArtifactGeneratorRegistry", () => {
 81→  test("generate returns correct output for a registered format", () => {
 82→    const registry = new ArtifactGeneratorRegistry();
 83→    registry.register(markdownGenerator);
 84→
 85→    const conversation = createConversation();
 86→    const expected = conversationToMarkdown(conversation);
 87→    const actual = registry.generate("markdown", conversation);
 88→
 89→    expect(actual).toBe(expected);
 90→  });
 91→
 92→  test("generate throws a clear error for an unknown format", () => {
 93→    const registry = new ArtifactGeneratorRegistry();
 94→
 95→    expect(() =>
 96→      registry.generate("unknown", createConversation()),
 97→    ).toThrowError(/unknown/i);
 98→  });
 99→
100→  test("register adds a custom generator that can be used via generate", () => {
101→    const registry = new ArtifactGeneratorRegistry();
102→    const customGenerator: ArtifactGenerator = {
103→      formatId: "custom",
104→      generate: () => "custom-output",
105→    };
106→
107→    registry.register(customGenerator);
108→    const result = registry.generate("custom", createConversation());
109→
110→    expect(result).toBe("custom-output");
111→  });
112→
113→  test("getAll returns all registered generators", () => {
114→    const registry = new ArtifactGeneratorRegistry();
115→    registry.register(markdownGenerator);
116→    registry.register(jsonGenerator);
117→
118→    const all = registry.getAll();
119→    expect(all).toHaveLength(2);
120→    expect(all.map((g) => g.formatId)).toContain("markdown");
121→    expect(all.map((g) => g.formatId)).toContain("json");
122→  });
123→
124→  test("registering a generator with duplicate formatId overwrites the previous one", () => {
125→    const registry = new ArtifactGeneratorRegistry();
126→    const gen1: ArtifactGenerator = {
127→      formatId: "test",
128→      generate: () => "first",
129→    };
130→    const gen2: ArtifactGenerator = {
131→      formatId: "test",
132→      generate: () => "second",
133→    };
134→
135→    registry.register(gen1);
136→    registry.register(gen2);
137→
138→    const result = registry.generate("test", createConversation());
139→    expect(result).toBe("second");
140→    expect(registry.getAll()).toHaveLength(1);
141→  });
142→});
