register(generator: ArtifactGenerator): void {
  if (this.generators.has(generator.formatId)) {
    throw new Error(
      `Artifact generator for format "${generator.formatId}" is already registered.`,
    );
  }
  this.generators.set(generator.formatId, generator);
}

input.old_string:
test("registering a generator with duplicate formatId overwrites the previous one", () => {
  const registry = new ArtifactGeneratorRegistry();
  const gen1: ArtifactGenerator = {
    formatId: "test",
    generate: () => "first",
  };
  const gen2: ArtifactGenerator = {
    formatId: "test",
    generate: () => "second",
  };

  registry.register(gen1);
  registry.register(gen2);

  const result = registry.generate("test", createConversation());
  expect(result).toBe("second");
  expect(registry.getAll()).toHaveLength(1);
});

